import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the custom CUDA kernel for optimized L2 normalization
l2_norm_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <math.h>
#include <type_traits>

template<typename T>
struct ComputeType {
    using type = float;  // Default to float for accumulation
};

template<>
struct ComputeType<double> {
    using type = double;
};

template<>
struct ComputeType<half> {
    using type = float;
};

template<typename T>
__global__ void l2_norm_kernel(const T* __restrict__ input, T* __restrict__ output, 
                               int batch_size, int dim) {
    using ComputeT = typename ComputeType<T>::type;

    const int batch_idx = blockIdx.x;
    const int tid = threadIdx.x;

    // Use 256 threads per block (power of 2 for reduction)
    const int threads = 256;

    // Shared memory for reduction - use ComputeT for accumulation
    __shared__ ComputeT sdata[256];

    // Each thread processes multiple elements
    ComputeT thread_sum = 0.0;

    // Process elements with stride equal to total threads
    // Explicitly cast to ComputeT to ensure correct precision
    for (int i = tid; i < dim; i += threads) {
        int idx = batch_idx * dim + i;
        ComputeT val = static_cast<ComputeT>(input[idx]);
        thread_sum += val * val;
    }

    // Parallel reduction
    sdata[tid] = thread_sum;
    __syncthreads();

    // Tree reduction
    for (int stride = threads / 2; stride > 0; stride >>= 1) {
        if (tid < stride) {
            sdata[tid] += sdata[tid + stride];
        }
        __syncthreads();
    }

    // Compute reciprocal of L2 norm (1 / sqrt(sum))
    ComputeT scale = 0.0;
    if (tid == 0) {
        // Use epsilon of same type as ComputeT
        const ComputeT epsilon = static_cast<ComputeT>(1e-8);
        ComputeT norm = sqrt(sdata[0] + epsilon);
        scale = static_cast<ComputeT>(1.0) / norm;
        sdata[0] = scale;
    }
    __syncthreads();

    scale = sdata[0];

    // Normalize elements with explicit type conversion
    for (int i = tid; i < dim; i += threads) {
        int idx = batch_idx * dim + i;
        ComputeT val = static_cast<ComputeT>(input[idx]);
        output[idx] = static_cast<T>(val * scale);
    }
}

torch::Tensor l2_norm_cuda(torch::Tensor input) {
    // Validate input tensor type
    TORCH_CHECK(input.is_cuda(), "Input must be a CUDA tensor");
    TORCH_CHECK(input.dim() == 2, "Input must be 2D (batch_size, dim)");
    TORCH_CHECK(input.scalar_type() == torch::kFloat16 || 
                input.scalar_type() == torch::kFloat32 || 
                input.scalar_type() == torch::kFloat64,
                "Input must be half, float, or double");

    auto batch_size = input.size(0);
    auto dim = input.size(1);
    auto output = torch::empty_like(input);

    const int threads = 256;
    const int blocks = batch_size;

    AT_DISPATCH_FLOATING_TYPES_AND_HALF(input.scalar_type(), "l2_norm_cuda", ([&] {
        l2_norm_kernel<scalar_t><<<blocks, threads>>>(
            input.data_ptr<scalar_t>(),
            output.data_ptr<scalar_t>(),
            batch_size,
            dim
        );
    }));

    cudaDeviceSynchronize();
    cudaError_t err = cudaGetLastError();
    TORCH_CHECK(err == cudaSuccess, "CUDA error: ", cudaGetErrorString(err));
    return output;
}
"""

l2_norm_cpp_source = "torch::Tensor l2_norm_cuda(torch::Tensor input);"

# Compile the inline CUDA code for L2 normalization
l2_norm_module = load_inline(
    name="l2_norm",
    cpp_sources=l2_norm_cpp_source,
    cuda_sources=l2_norm_source,
    functions=["l2_norm_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[""],
    with_cuda=True,
)

class ModelNew(nn.Module):
    """
    Optimized L2 normalization model with custom CUDA kernel.
    """
    def __init__(self):
        super(ModelNew, self).__init__()

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        """
        Applies L2 normalization using custom CUDA kernel.

        Args:
            x (torch.Tensor): Input tensor of shape (batch_size, dim).

        Returns:
            torch.Tensor: L2 normalized tensor, same shape as input.
        """
        # Ensure tensor is on CUDA device
        if not x.is_cuda:
            x = x.cuda()

        # Additional validation
        if x.dim() != 2:
            raise ValueError(f"Input must be 2D, got shape {x.shape}")

        return l2_norm_module.l2_norm_cuda(x)
